card.example:
const { div, span, h3 } = tags;
div({ class: css('cc-frame-sm') },
  Card({},
    Card.Header({},
      div({ class: css('cc-bar') },
        span({ class: css('cc-label') }, 'THREAT LEVEL'),
        span({ class: css('cc-indicator cc-indicator-warn cc-blink') })
      )
    ),
    Card.Body({},
      span({ class: css('cc-data _heading2') }, '42')
    ),
    Card.Footer({ class: css('cc-bar-bottom') },
      span({ class: css('cc-label') }, 'UPDATED 14:32:07')
    )
  )
)

kpi.example:
